const customers = $input.all().map(i => i.json);
const now = Date.now();
const ninetyDaysMs = 90 * 24 * 60 * 60 * 1000;

const dormant = customers.filter(c => {
  if (!c.updated_at) return false;
  const elapsed = now - new Date(c.updated_at).getTime();
  if (elapsed < ninetyDaysMs) return false;
  if (!c.email && !c.phone) return false;
  return true;
});

if (dormant.length === 0) return [];

return dormant.map(c => {
  const daysSince = Math.floor((now - new Date(c.updated_at).getTime()) / (24 * 60 * 60 * 1000));
  return { json: { ...c, days_dormant: daysSince } };
});

function buildEmailHtml(options) {
  const { subject, headline, bodyHtml, ctaText, ctaUrl, previewText } = options;
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${subject}</title></head><body style="margin:0;padding:0;background-color:#f5f5f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;"><span style="display:none;max-height:0;overflow:hidden;">${previewText || ''}</span><table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f5f0;"><tr><td align="center" style="padding:20px;"><table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);"><tr><td style="background:#2D5A27;padding:20px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:20px;font-weight:bold;">TotalGuard Yard Care</td><td align="right" style="color:#ffffff;font-size:14px;"><a href="tel:6085356057" style="color:#ffffff;text-decoration:none;">(608) 535-6057</a></td></tr><tr><td colspan="2" style="color:#C5A55A;font-size:12px;padding-top:4px;">Madison's Most Trusted Yard Care</td></tr></table></td></tr><tr><td style="padding:30px 30px 10px;"><h1 style="margin:0;color:#2D5A27;font-size:24px;">${headline}</h1></td></tr><tr><td style="padding:10px 30px 20px;color:#1a1a1a;font-size:15px;line-height:1.6;">${bodyHtml}</td></tr><tr><td style="padding:0 30px 20px;" align="center"><table cellpadding="0" cellspacing="0"><tr><td style="background:#2D5A27;border-radius:6px;padding:14px 32px;"><a href="${ctaUrl}" style="color:#ffffff;text-decoration:none;font-weight:bold;font-size:16px;display:inline-block;">${ctaText}</a></td></tr></table></td></tr><tr><td style="padding:0 30px 20px;text-align:center;"><div style="color:#555;font-size:13px;">Prefer to talk? <a href="tel:6085356057" style="color:#2D5A27;font-weight:bold;">(608) 535-6057</a></div></td></tr><tr><td style="padding:10px 30px;text-align:center;border-top:1px solid #eee;"><div style="color:#888;font-size:11px;">Licensed &amp; Insured | 4.9 Google Rating | 500+ Properties | Satisfaction Guaranteed</div></td></tr><tr><td style="background:#1a1a1a;padding:24px 30px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="color:#ffffff;font-size:14px;font-weight:bold;">TotalGuard Yard Care</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:6px;">7610 Welton Dr, Madison, WI 53711</td></tr><tr><td style="color:#aaa;font-size:12px;padding-top:4px;"><a href="tel:6085356057" style="color:#C5A55A;">(608) 535-6057</a> | <a href="mailto:totalguardllc@gmail.com" style="color:#C5A55A;">totalguardllc@gmail.com</a></td></tr><tr><td style="padding-top:10px;"><a href="https://facebook.com/totalguardyard/" style="color:#C5A55A;font-size:12px;text-decoration:none;margin-right:10px;">Facebook</a> <a href="https://instagram.com/totalguardyardcare" style="color:#C5A55A;font-size:12px;text-decoration:none;margin-right:10px;">Instagram</a> <a href="https://g.page/r/CRW5Dsg2JgwBEBM/review" style="color:#C5A55A;font-size:12px;text-decoration:none;">Google</a></td></tr><tr><td style="color:#666;font-size:10px;padding-top:10px;">Serving Madison, Middleton, Waunakee, Monona, Sun Prairie, Fitchburg, Verona, McFarland, Cottage Grove, DeForest, Oregon &amp; Stoughton</td></tr></table></td></tr></table></td></tr></table></body></html>`;
}

const results = [];

for (const item of $input.all()) {
  const c = item.json;
  const name = c.first_name || 'there';

  if (c.phone) {
    results.push({
      json: {
        channel: 'sms',
        lead_id: c.id,
        to_phone: c.phone,
        sms_body: `Hi ${name}! It's been a while since TotalGuard took care of your yard. We miss you! Book this week and get 10% off your first service back. Call (608) 535-6057 or visit tgyardcare.com \u2014 TotalGuard`,
        workflow_name: 'TG-63',
        sms_type: 'winback'
      }
    });
  }

  if (c.email) {
    const subject = `We miss you, ${name}! Come back to TotalGuard`;
    const html = buildEmailHtml({
      subject,
      headline: `We Miss You, ${name}!`,
      bodyHtml: `<p>Hi ${name},</p><p>It's been a while since TotalGuard took care of your yard, and we'd love to have you back. Your property deserves the same professional care it used to get.</p><p style="background:#f0f8f0;padding:16px;border-radius:6px;border:2px solid #2D5A27;text-align:center;"><strong style="font-size:18px;color:#2D5A27;">Welcome Back: 10% Off Your First Service</strong><br><span style="color:#555;">Use this exclusive offer to get started again.</span></p><p>Whether you need mowing, cleanup, fertilization, or any of our services &mdash; we're ready when you are. Same trusted team, same quality results.</p>`,
      ctaText: 'Reclaim My 10% Discount',
      ctaUrl: 'https://tgyardcare.com',
      previewText: `${name}, it's been a while! Come back to TotalGuard and save 10%.`
    });

    results.push({
      json: {
        channel: 'email',
        lead_id: c.id,
        to_email: c.email,
        subject,
        html_body: html,
        workflow_name: 'TG-63',
        email_type: 'winback'
      }
    });
  }
}

return results;

